#!/usr/bin/env python3
import json
import os
import sys
import requests
from datetime import datetime


def _read_json(path: str) -> dict:
    with open(path, "r", encoding="utf-8") as f:
        obj = json.load(f)
    if not isinstance(obj, dict):
        raise ValueError(f"JSON at {path} must be an object")
    return obj


def _as_list(x):
    if x is None:
        return []
    if isinstance(x, list):
        return x
    return [x]


def _to_bool(x):
    if isinstance(x, bool):
        return x
    if isinstance(x, (int, float)):
        return bool(x)
    if isinstance(x, str):
        return x.strip().lower() in {"true", "1", "yes", "y", "on"}
    return False


def _parse_date_like(v):
    """Return (date_str, time_str_or_none). Accepts YYYY-MM-DD, ISO datetime, dict."""
    if v is None:
        return None, None

    if isinstance(v, dict):
        # already looks like monday date payload
        d = v.get("date") or v.get("start") or v.get("value")
        t = v.get("time")
        if isinstance(d, str) and d.strip():
            return d.strip(), (t.strip() if isinstance(t, str) and t.strip() else None)

    if isinstance(v, (int, float)):
        # unix seconds
        dt = datetime.utcfromtimestamp(float(v))
        return dt.strftime("%Y-%m-%d"), dt.strftime("%H:%M:%S")

    if isinstance(v, str):
        s = v.strip()
        if not s:
            return None, None
        # YYYY-MM-DD
        if len(s) == 10 and s[4] == "-" and s[7] == "-":
            return s, None
        # try ISO
        try:
            dt = datetime.fromisoformat(s.replace("Z", "+00:00"))
            return dt.date().isoformat(), dt.time().strftime("%H:%M:%S")
        except Exception:
            # best-effort: leave as date
            return s[:10], None

    # fallback
    return None, None


def _get_all_users(api_url, token, api_version):
    """Fetch all users from the Monday account to resolve emails/names to IDs."""
    query = """
    query {
      users {
        id
        name
        email
      }
    }
    """
    data = _monday_request(api_url, token, api_version, query, {})
    return (data.get("data") or {}).get("users") or []


def _resolve_person_identifier(value_str, users):
    """Try to match a string (email or name) to a monday user ID. Returns int or None."""
    if not users or not value_str:
        return None
    v = value_str.strip().lower()
    # Exact email match
    for u in users:
        if (u.get("email") or "").strip().lower() == v:
            return int(u["id"])
    # Exact name match
    for u in users:
        if (u.get("name") or "").strip().lower() == v:
            return int(u["id"])
    # Partial name match (contains)
    for u in users:
        if v in (u.get("name") or "").strip().lower():
            return int(u["id"])
    return None


def _normalize_people_value(raw, users=None):
    """
    Accepts:
      - 12345
      - "12345" or "12345,67890"
      - "user@email.com" or "John Doe" (resolved via monday users API)
      - [123, 456]
      - [{"id":123,"kind":"person"}, ...]
      - {"personsAndTeams":[...]}
    Returns monday JSON object: {"personsAndTeams":[{"id":..,"kind":"person"|"team"}]}

    Community-confirmed canonical structure uses personsAndTeams with id+kind.
    """
    if raw is None:
        return {}

    if isinstance(raw, dict):
        if "personsAndTeams" in raw and isinstance(raw["personsAndTeams"], list):
            return {"personsAndTeams": raw["personsAndTeams"]}
        if "id" in raw and "kind" in raw:
            return {"personsAndTeams": [raw]}

    # comma-separated string
    if isinstance(raw, str):
        s = raw.strip()
        if not s:
            return {}
        parts = [p.strip() for p in s.split(",") if p.strip()]
        ids = []
        for p in parts:
            try:
                ids.append(int(p))
            except Exception:
                resolved = _resolve_person_identifier(p, users)
                if resolved is not None:
                    ids.append(resolved)
        return {"personsAndTeams": [{"id": i, "kind": "person"} for i in ids]}

    if isinstance(raw, (int, float)):
        return {"personsAndTeams": [{"id": int(raw), "kind": "person"}]}

    if isinstance(raw, list):
        out = []
        for x in raw:
            if isinstance(x, dict) and "id" in x:
                out.append({"id": int(x["id"]), "kind": x.get("kind", "person")})
            elif isinstance(x, str):
                try:
                    out.append({"id": int(x.strip()), "kind": "person"})
                except Exception:
                    resolved = _resolve_person_identifier(x.strip(), users)
                    if resolved is not None:
                        out.append({"id": resolved, "kind": "person"})
            elif isinstance(x, (int, float)):
                out.append({"id": int(x), "kind": "person"})
        return {"personsAndTeams": out}

    return {}


def _normalize_checkbox_value(raw):
    """monday checkbox expects JSON like {"checked":"true"|"false"} (string) per API behavior notes."""
    return {"checked": "true" if _to_bool(raw) else "false"}


def _normalize_status_value(raw):
    """Accepts string label or {label:"..."} or raw dict."""
    if raw is None:
        return {}
    if isinstance(raw, dict):
        return raw
    if isinstance(raw, str):
        s = raw.strip()
        if not s:
            return {}
        return {"label": s}
    return {"label": str(raw)}


def _normalize_dropdown_value(raw):
    """
    Dropdown commonly accepts ids or labels arrays. We support:
      - "Alpha" -> {labels:["Alpha"]}
      - "A,B" -> {labels:["A","B"]}
      - ["A","B"] -> {labels:[...]}
      - [1,2] -> {ids:[1,2]}
      - {ids:[...]} or {labels:[...]} passthrough
    """
    if raw is None:
        return {}
    if isinstance(raw, dict):
        return raw
    if isinstance(raw, str):
        s = raw.strip()
        if not s:
            return {}
        parts = [p.strip() for p in s.split(",") if p.strip()]
        return {"labels": parts}
    if isinstance(raw, list):
        if all(isinstance(x, (int, float)) for x in raw):
            return {"ids": [int(x) for x in raw]}
        return {"labels": [str(x).strip() for x in raw if str(x).strip()]}
    if isinstance(raw, (int, float)):
        return {"ids": [int(raw)]}
    return {"labels": [str(raw)]}


def _normalize_date_value(raw):
    d, t = _parse_date_like(raw)
    if not d:
        return {}
    payload = {"date": d}
    if t:
        payload["time"] = t
    return payload


def _normalize_numbers_value(raw):
    if raw is None:
        return ""
    if isinstance(raw, (int, float)):
        return str(raw)
    if isinstance(raw, str):
        return raw.strip()
    return str(raw)


def _normalize_link_value(raw):
    """Accepts 'url', or {url,text}."""
    if raw is None:
        return {}
    if isinstance(raw, dict):
        return raw
    s = str(raw).strip()
    if not s:
        return {}
    return {"url": s, "text": s}


def _normalize_email_value(raw):
    if raw is None:
        return {}
    if isinstance(raw, dict):
        return raw
    s = str(raw).strip()
    if not s:
        return {}
    return {"email": s, "text": s}


def _normalize_phone_value(raw):
    if raw is None:
        return {}
    if isinstance(raw, dict):
        return raw
    s = str(raw).strip()
    if not s:
        return {}
    return {"phone": s, "text": s}


def _monday_request(api_url, token, api_version, query, variables):
    headers = {
        "Authorization": token,
        "Content-Type": "application/json",
    }
    # monday has explicit API versioning docs + migration track; we expose config.
    if api_version:
        headers["API-Version"] = api_version

    resp = requests.post(api_url, headers=headers, json={"query": query, "variables": variables}, timeout=30)
    text = resp.text
    try:
        payload = resp.json()
    except Exception:
        raise RuntimeError(f"Non-JSON response (status {resp.status_code}): {text[:500]}")

    if resp.status_code >= 400:
        raise RuntimeError(f"HTTP {resp.status_code}: {payload}")

    if "errors" in payload and payload["errors"]:
        raise RuntimeError(f"GraphQL errors: {payload['errors']}")

    return payload


def _get_board_columns(api_url, token, api_version, board_id: int):
    query = """
    query ($board_id: [ID!]) {
      boards (ids: $board_id) {
        id
        columns {
          id
          type
        }
      }
    }
    """
    data = _monday_request(api_url, token, api_version, query, {"board_id": str(board_id)})
    boards = (((data.get("data") or {}).get("boards")) or [])
    if not boards:
        raise RuntimeError(f"Board not found or inaccessible: {board_id}")
    cols = boards[0].get("columns") or []
    return {c["id"]: (c.get("type") or "") for c in cols if isinstance(c, dict) and c.get("id")}


def _normalize_column_values(raw_map: dict, col_types: dict, users=None):
    out = {}
    for col_id, raw_val in (raw_map or {}).items():
        # allow callers to pass non-string keys; monday requires string column IDs
        col_key = str(col_id)
        ctype = (col_types.get(col_key) or "").lower()

        # If caller already sends a dict with explicit shape, we still might need to coerce
        # for known tricky columns; otherwise pass through.
        if ctype in {"people", "person"}:
            out[col_key] = _normalize_people_value(raw_val, users)
        elif ctype == "checkbox":
            out[col_key] = _normalize_checkbox_value(raw_val)
        elif ctype == "date":
            out[col_key] = _normalize_date_value(raw_val)
        elif ctype == "status":
            out[col_key] = _normalize_status_value(raw_val)
        elif ctype == "dropdown":
            out[col_key] = _normalize_dropdown_value(raw_val)
        elif ctype in {"numbers", "number"}:
            # numbers can be sent as string/simple
            out[col_key] = _normalize_numbers_value(raw_val)
        elif ctype == "email":
            out[col_key] = _normalize_email_value(raw_val)
        elif ctype == "phone":
            out[col_key] = _normalize_phone_value(raw_val)
        elif ctype == "link":
            out[col_key] = _normalize_link_value(raw_val)
        else:
            # default: send as simple string when possible, else JSON passthrough
            if isinstance(raw_val, (dict, list)):
                out[col_key] = raw_val
            elif raw_val is None:
                out[col_key] = ""
            else:
                out[col_key] = str(raw_val)

    return out


def main():
    connector_path = os.environ.get("CONNECTOR_JSON_PATH")
    if not connector_path:
        raise RuntimeError("CONNECTOR_JSON_PATH env missing")

    connector = _read_json(connector_path)
    auth = connector.get("auth") or {}
    cfg = connector.get("configuration") or {}

    token = auth.get("monday_api_token")
    if not token:
        raise RuntimeError("auth.monday_api_token missing")

    api_url = cfg.get("api_url") or "https://api.monday.com/v2"
    api_version = cfg.get("api_version") or ""

    board_id = int(cfg["board_id"])
    group_id = str(cfg["group_id"])
    item_name = str(cfg["item_name"])
    raw_column_values = cfg.get("column_values") or {}
    create_labels_if_missing = bool(cfg.get("create_labels_if_missing"))

    # Optional placement arguments added in API versions 2024-04+
    position_relative_method = cfg.get("position_relative_method")
    relative_to = cfg.get("relative_to")

    return_fields = cfg.get("return_fields") or ["id"]
    if not isinstance(return_fields, list) or not return_fields:
        return_fields = ["id"]

    # Discover board columns so we can normalize tricky types properly
    col_types = _get_board_columns(api_url, token, api_version, board_id)

    # Fetch users only when person columns exist (to resolve email/name references)
    _users_cache = []
    has_person_cols = any(ct.lower() in {"people", "person"} for ct in col_types.values())
    if has_person_cols and raw_column_values:
        try:
            _users_cache = _get_all_users(api_url, token, api_version)
        except Exception:
            _users_cache = []

    normalized_values_obj = _normalize_column_values(raw_column_values, col_types, _users_cache)

    # monday expects column_values argument as JSON string in create_item
    column_values_str = json.dumps(normalized_values_obj, ensure_ascii=False)

    # Build mutation dynamically with safe selection set
    selection = "\n".join([f"        {f}" for f in return_fields if isinstance(f, str) and f.strip()])
    if not selection.strip():
        selection = "        id"

    mutation = f"""
    mutation ($board_id: ID!, $group_id: String!, $item_name: String!, $column_values: JSON!, $create_labels_if_missing: Boolean, $relative_to: ID, $position_relative_method: PositionRelative) {{
      create_item(
        board_id: $board_id,
        group_id: $group_id,
        item_name: $item_name,
        column_values: $column_values,
        create_labels_if_missing: $create_labels_if_missing,
        relative_to: $relative_to,
        position_relative_method: $position_relative_method
      ) {{
{selection}
      }}
    }}
    """

    variables = {
        "board_id": str(board_id),
        "group_id": group_id,
        "item_name": item_name,
        "column_values": column_values_str,
        "create_labels_if_missing": create_labels_if_missing,
        "relative_to": str(relative_to) if relative_to is not None else None,
        "position_relative_method": position_relative_method,
    }

    result = _monday_request(api_url, token, api_version, mutation, variables)
    created = ((result.get("data") or {}).get("create_item")) or {}

    # Print EXACTLY one JSON object (your orchestrator contract)
    print(json.dumps({
        "created_item": created,
        "normalized_column_values": normalized_values_obj
    }, ensure_ascii=False))


if __name__ == "__main__":
    try:
        main()
    except Exception as e:
        # still emit JSON for easier debugging
        print(json.dumps({"error": str(e)}, ensure_ascii=False))
        sys.exit(1)
